// src/server/notepad-hub.ts
// Server-only in-memory pub/sub hub for the collaborative notepad.

export type NotepadEvent =
  | { type: "snapshot"; text: string }
  | { type: "update"; text: string; clientId: string };

export type Subscriber = (event: NotepadEvent) => void;

let documentText = "";
const subscribers = new Set<Subscriber>();

export function getDocumentText(): string {
  return documentText;
}

export function setDocumentText(text: string): void {
  documentText = text;
}

export function subscribe(fn: Subscriber): () => void {
  subscribers.add(fn);
  return () => {
    subscribers.delete(fn);
  };
}

export function broadcast(event: NotepadEvent): void {
  for (const subscriber of subscribers) {
    subscriber(event);
  }
}
```

