/**
 * Server-only in-memory publish/subscribe hub for the collaborative notepad.
 *
 * This module keeps the latest document text and a set of active subscribers
 * (one per connected SSE client). It is only ever imported by the
 * `/api/notepad` endpoint, which runs exclusively on the server, so none of
 * this logic ever ends up in a client bundle.
 *
 * Everything lives in process memory: there are no external services,
 * databases, or third-party APIs involved.
 */

/** An edit broadcast to every connected SSE client. */
export interface NotepadUpdateEvent {
  readonly type: "update";
  readonly text: string;
  readonly clientId: string;
}

/** The only kind of event currently broadcast by the hub. */
export type NotepadEvent = NotepadUpdateEvent;

/** A callback invoked whenever a new edit is broadcast. */
export type NotepadSubscriber = (event: NotepadEvent) => void;

/** The latest known document text. */
let documentText = "";

/** The set of currently connected subscribers. */
const subscribers = new Set<NotepadSubscriber>();

/** Returns the latest document text held by the server. */
export function getDocumentText(): string {
  return documentText;
}

/** Replaces the document text held by the server. */
export function setDocumentText(text: string): void {
  documentText = text;
}

/**
 * Registers a subscriber so it receives every subsequent broadcast.
 * Returns an `unsubscribe` function that removes the subscriber; it MUST be
 * called when a client disconnects so the connection is cleaned up.
 */
export function subscribe(subscriber: NotepadSubscriber): () => void {
  subscribers.add(subscriber);
  return function unsubscribe(): void {
    subscribers.delete(subscriber);
  };
}

/**
 * Broadcasts an edit to every currently connected subscriber. A subscriber
 * that throws while handling the event is skipped so a single broken client
 * can't prevent the others from receiving the update.
 */
export function broadcast(event: NotepadEvent): void {
  // Copy the set so a subscriber unsubscribing during iteration doesn't
  // interfere with the loop.
  for (const subscriber of Array.from(subscribers)) {
    try {
      subscriber(event);
    } catch {
      /* ignore a single failing subscriber */
    }
  }
}

import type { RequestHandler } from "@builder.io/qwik-city";
import {
  broadcast,
  getDocumentText,
  setDocumentText,
  subscribe,
} from "../../../server/notepad-hub";

/**
 * GET /api/notepad
 *
 * Opens a long-lived Server-Sent Events stream. Immediately upon connection it
 * emits a single `snapshot` event carrying the latest document text, then it
 * forwards every subsequent edit (broadcast by POST below) as an `update`
 * event. The connection stays open until the client disconnects, at which
 * point the subscriber is removed and the stream is closed.
 */
export const onGet: RequestHandler = async ({
  headers,
  getWritableStream,
  signal,
}) => {
  // SSE response headers. `no-transform` asks intermediaries not to alter the
  // stream and `X-Accel-Buffering: no` disables buffering on nginx.
  headers.set("Content-Type", "text/event-stream");
  headers.set("Cache-Control", "no-cache, no-transform");
  headers.set("Connection", "keep-alive");
  headers.set("X-Accel-Buffering", "no");

  const stream = getWritableStream();
  const writer = stream.getWriter();
  const encoder = new TextEncoder();

  const writeEvent = (raw: string): void => {
    writer.write(encoder.encode(raw));
  };

  // 1. Immediately send the current document text as a `snapshot` event.
  writeEvent(
    `event: snapshot\ndata: ${JSON.stringify({ text: getDocumentText() })}\n\n`,
  );

  // 2. Forward every broadcast edit to this client as an `update` event.
  const unsubscribe = subscribe((event) => {
    if (event.type === "update") {
      writeEvent(
        `event: update\ndata: ${JSON.stringify({
          text: event.text,
          clientId: event.clientId,
        })}\n\n`,
      );
    }
  });

  // 3. Keep the connection open until the client disconnects. The request's
  //    AbortSignal fires when the underlying socket closes.
  await new Promise<void>((resolve) => {
    if (signal.aborted) {
      resolve();
    } else {
      signal.addEventListener("abort", () => resolve(), { once: true });
    }
  });

  // 4. Clean up: stop receiving broadcasts and close the stream.
  unsubscribe();
  await writer.close().catch(() => {
    /* the stream may already be closed when the client disconnected */
  });
};

/**
 * POST /api/notepad
 *
 * Accepts a JSON edit `{"text": string, "clientId": string}`, updates the
 * server-held document text, broadcasts an `update` event carrying that same
 * text and clientId to all connected SSE clients, and responds with
 * HTTP 200 and body `{"ok": true}`.
 */
export const onPost: RequestHandler = async ({ parseBody, json }) => {
  const body = (await parseBody()) as
    | { text?: unknown; clientId?: unknown }
    | null;

  const text = typeof body?.text === "string" ? body.text : "";
  const clientId = typeof body?.clientId === "string" ? body.clientId : "";

  // Update the stored document text.
  setDocumentText(text);

  // Broadcast the edit to every connected SSE client.
  broadcast({ type: "update", text, clientId });

  // Acknowledge the edit.
  return json(200, { ok: true });
};

import { component$, useSignal, useVisibleTask$ } from "@builder.io/qwik";
import type { DocumentHead } from "@builder.io/qwik-city";

export default component$(() => {
  // Reactive state holding the current document text shown in the textarea.
  const text = useSignal("");
  // A stable, unique id for this browser tab. Used to ignore our own edits
  // when they are echoed back over the SSE stream.
  const clientId = useSignal("");

  // All browser-only APIs (EventSource) belong inside useVisibleTask$.
  useVisibleTask$(() => {
    // Generate a unique id for this tab.
    clientId.value =
      Math.random().toString(36).slice(2) + Date.now().toString(36);

    const eventSource = new EventSource("/api/notepad");

    // On connect the server sends the latest document text as a snapshot.
    eventSource.addEventListener("snapshot", (event) => {
      const data = JSON.parse((event as MessageEvent).data) as {
        text: string;
      };
      text.value = data.text;
    });

    // Every broadcast edit arrives as an update. Ignore edits that originated
    // from this same tab so we don't clobber in-progress typing.
    eventSource.addEventListener("update", (event) => {
      const data = JSON.parse((event as MessageEvent).data) as {
        text: string;
        clientId: string;
      };
      if (data.clientId === clientId.value) {
        return;
      }
      text.value = data.text;
    });

    // Close the connection when the task is cleaned up (e.g. on navigation).
    return () => {
      eventSource.close();
    };
  });

  return (
    <main
      style={{
        maxWidth: "800px",
        margin: "2rem auto",
        padding: "0 1rem",
        fontFamily:
          "ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, Roboto, sans-serif",
      }}
    >
      <h1>Collaborative Notepad</h1>
      <p style={{ color: "#666" }}>
        Open this page in another browser tab to edit together in real time.
      </p>
      <textarea
        value={text.value}
        onInput$={async (event) => {
          const value = (event.target as HTMLTextAreaElement).value;
          // Optimistically update local state so typing feels instant.
          text.value = value;
          // Broadcast the new text to all other connected clients.
          await fetch("/api/notepad", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ text: value, clientId: clientId.value }),
          });
        }}
        rows={20}
        placeholder="Start typing..."
        style={{
          width: "100%",
          fontSize: "1rem",
          padding: "0.75rem",
          borderRadius: "8px",
          border: "1px solid #ccc",
          boxSizing: "border-box",
          fontFamily: "ui-monospace, SFMono-Regular, Menlo, monospace",
          resize: "vertical",
        }}
      />
    </main>
  );
});

export const head: DocumentHead = {
  title: "Collaborative Notepad",
  meta: [
    {
      name: "description",
      content: "Real-time collaborative notepad built with Qwik City and SSE",
    },
  ],
};

